def sum_evens(nums):
    total = 0
    for n in nums:
        if n % 2 == 0:
            total += n
    return total

# cd_v02: count_target bug - starts at index 1, misses index 0
def count_target(nums, target):
    count = 0
    for i in range(len(nums)):
        if nums[i] == target:
            count += 1
    return count

# cd_v03: average bug - divides by len-1 instead of len
def average(nums):
    total = 0
    for n in nums:
        total += n
    return total / len(nums)

# cg_v01: run_length_encode
def run_length_encode(s):
    if not s:
        return []
    result = []
    prev = s[0]
    count = 1
    for ch in s[1:]:
        if ch == prev:
            count += 1
        else:
            result.append((prev, count))
            prev = ch
            count = 1
    result.append((prev, count))
    return result

# cg_v02: interval_intersection
def interval_intersection(a, b):
    result = []
    i = j = 0
    while i < len(a) and j < len(b):
        s = max(a[i][0], b[j][0])
        e = min(a[i][1], b[j][1])
        if s <= e:
            result.append([s, e])
        if a[i][1] < b[j][1]:
            i += 1
        else:
            j += 1
    return result

